let counters = { R: 112, F: 515, V: 10, T: 8, E: 4, N: 0 };

export function nextId(prefix: 'R' | 'F' | 'V' | 'T' | 'E' | 'N'): string {
  counters[prefix]++;
  const pad = prefix === 'R' || prefix === 'F' ? 3 : prefix === 'N' ? 4 : 3;
  return `${prefix}-${String(counters[prefix]).padStart(pad, '0')}`;
}
